const InstitutionDetails: React.FC = () => {
  const institutionData = useLiveQuery(() => db.institutions.toCollection().first());
  const [activeTab, setActiveTab] = useState<'particulars' | 'location' | 'operations'>('particulars');
  const [formData, setFormData] = useState<Partial<Institution>>({});
  const [isSaving, setIsSaving] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);

  useEffect(() => {
    if (institutionData) {
      setFormData(institutionData);
    }
  }, [institutionData]);

  const handleSave = async () => {
    setIsSaving(true);
    try {
      if (formData.id) {
        await db.institutions.update(formData.id, formData);
      } else {
        await db.institutions.add(formData as Institution);
      }
      setSaveSuccess(true);
      setTimeout(() => setSaveSuccess(false), 3000);
    } catch (error) {
      console.error("Failed to save institution data:", error);
    } finally {
      setIsSaving(false);
    }
  };

  if (!institutionData && !formData.name) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="animate-pulse text-slate-400 font-bold uppercase tracking-widest text-xs">Loading Institution Profile...</div>
      </div>
    );
  }

  const TabButton: React.FC<{ id: string, label: string, icon: React.ReactNode }> = ({ id, label, icon }) => (
    <button 
