// Using named import for Dexie and fixing the nested Table type for staff.
// This ensures EMISDatabase correctly inherits instance methods like 'version' from Dexie.
export class EMISDatabase extends Dexie {
  learners!: Table<Learner>;
  staff!: Table<Staff>;
  infrastructure!: Table<Infrastructure>;
  institutions!: Table<Institution>;

  constructor() {
    super('Uganda_EMIS_PrePrimary');
    // Defining database schema versions and stores.
    this.version(2).stores({
      learners: '++id, lin, nin, surname, gender, class, status',
      staff: '++id, nin, fullName, type, status',
      infrastructure: '++id, type, condition',
      institutions: '++id, name, emisNumber'
    });
  }
}

